import io
import itertools
import os
from pathlib import PurePosixPath, PurePath
from typing import List

import boto3
import botocore.exceptions

from geosat.tools.urlprotocol.urlprotocol import UrlProtocol
from geosat.tools.urlprotocol.deferred_stream import DeferredStream


class S3UrlProtocol(UrlProtocol):
    """Protocol that handles requests to Amazon S3"""

    client = boto3.client("s3")
    resource = boto3.resource("s3")

    @staticmethod
    def get_scheme() -> str:
        return "s3"

    def exists(self, url: str):
        bucket_name, key = self._split_s3_url(url)
        try:
            self.resource.Object(bucket_name, key).load()
        except botocore.exceptions.ClientError as ex:
            if ex.response["Error"]["Code"] == "404":
                return False
            else:
                raise
        else:
            return True

    def _join_s3_url(self, bucket_name, key):
        return self.get_scheme() + "://" + str(PurePosixPath(bucket_name, key))

    def _split_s3_url(self, url: str) -> tuple:
        _, body = self.split(url)
        bucket_name, _, key = body.partition("/")
        return bucket_name, key

    def _get_bucket_and_key(self, url: str) -> tuple:
        bucket_name, key = self._split_s3_url(url)
        bucket = self.resource.Bucket(bucket_name)
        return bucket, key

    def integrate_path(self, url: str, path: PurePath) -> str:
        bucket_name, key = self._split_s3_url(url)
        return self._join_s3_url(bucket_name, str(PurePosixPath(key) / path.name))

    def extract_path(self, url: str) -> PurePath:
        _, key = self._split_s3_url(url)
        return PurePosixPath("/", key)

    def list(self, url: str) -> list:
        bucket_name, key = self._split_s3_url(url)
        directory_key = str(PurePosixPath(key)) + "/"
        paginator = self.client.get_paginator("list_objects")
        iterator = paginator.paginate(
            Bucket=bucket_name,
            Prefix=directory_key,
            Delimiter="/",
            PaginationConfig={"PageSize": None},
        )
        files, sub_folders = [], []
        for element in iterator:
            try:
                for file_info in element["Contents"]:
                    files.append(file_info["Key"])
            except KeyError:
                pass
            try:
                for keys_info in element["CommonPrefixes"]:
                    sub_folders.append(keys_info["Prefix"])
            except KeyError:
                pass
        return [
            self._join_s3_url(bucket_name, key)
            for key in itertools.chain(files, sub_folders)
            if key != directory_key
        ]

    def request(self, url: str) -> List[str]:
        bucket, key = self._get_bucket_and_key(url)
        return [
            self._join_s3_url(bucket.name, content.key)
            for content in bucket.objects.filter(Prefix=key)
        ]

    def pull(self, url: str) -> str:
        """Pulls the S3 file to the local disk
        The pulled file will be written in the current working dir
        """
        bucket, key = self._get_bucket_and_key(url)
        local = self.extract_path(url).name
        if not os.path.exists(local):
            try:
                bucket.download_file(key, local)
            except botocore.exceptions.ClientError as ex:
                if ex.response["Error"]["Code"] == "404":
                    raise FileNotFoundError(url)
                else:
                    raise
        return local

    def push(self, url: str) -> str:
        local = self.extract_path(url).name
        bucket, key = self._get_bucket_and_key(url)
        bucket.upload_file(local, key)
        return local

    def receive(self, url: str, stream):
        bucket, key = self._get_bucket_and_key(url)
        try:
            bucket.download_fileobj(key, stream)
        except botocore.exceptions.ClientError as ex:
            if ex.response["Error"]["Code"] == "404":
                raise FileNotFoundError(url)
            else:
                raise

    def send(self, url: str, stream):
        bucket, key = self._get_bucket_and_key(url)
        bucket.upload_fileobj(stream, key)

    def delete_cache(self, url: str) -> str:
        local = self.extract_path(url).name
        try:
            os.remove(local)
        except FileNotFoundError:
            pass
        return local

    def remove(self, url: str):
        bucket, key = self._get_bucket_and_key(url)
        bucket.Object(key).delete()

    def open(self, url: str, mode: str):
        bucket, key = self._get_bucket_and_key(url)
        if "r" in mode:
            res = bucket.Object(key).get()
            if "b" not in mode:
                return io.StringIO(res["Body"].read().decode())
            # TODO Replace this by `return res["Body"]`, when new version of lazrs is handling cloud decompression without seeking
            return io.BytesIO(res["Body"].read())
        elif "w" in mode:
            internal_stream = io.BytesIO() if "b" in mode else io.StringIO()
            return DeferredStream(
                internal_stream,
                # Body accepts both bytes and str
                lambda stream: bucket.Object(key).put(Body=stream.getvalue()),
            )
